import { Component, OnDestroy, OnInit } from '@angular/core';
import { ContactService } from '../providers/contact/contact.service';
import { environment } from '../../environments/environment';
import { ToastrManager } from 'ng6-toastr-notifications';
import { ActivatedRoute } from '@angular/router';
import { FormBuilder, FormGroup, Validators, FormArray, FormControl, AbstractControl } from '@angular/forms';
import { PageService } from '../providers/page/page.service';
import { Meta, Title } from '@angular/platform-browser';
import { SearchCountryField, TooltipLabel, CountryISO } from 'ngx-intl-tel-input';
import { LazyLoaderService } from '../services/lazy-loader.service';
export { };
declare global {
	interface Window {
		Calendly: any;
	}
}

@Component({
	selector: 'app-contact',
	templateUrl: './contact.component.html',
	styleUrls: ['./contact.component.scss']
})
export class ContactComponent implements OnInit, OnDestroy {

	baseUrl: any;
	title = 'Contact Us';
	model: any = {
		name: null,
		email: null,
		message: null,
		phone: null,
		subject: []
	}
	submitted = false;
	error = {};
	selectedSubj: any = [];
	isWebsitesel = false;
	isBrandingsel = false;
	isGraphicsel = false;
	isSeosel = false;
	isEnterpricesel = false;
	isEcommerce = false;
	selectedSub: any;
	addCareerForm: FormGroup;
	throw_msg: any;
	msg_success: boolean = false;
	msg_danger: boolean = false;
	subject: any = [];
	SearchCountryField = SearchCountryField;
	TooltipLabel = TooltipLabel;
	CountryISO = CountryISO;
	preferredCountries: CountryISO[] = [CountryISO.India, CountryISO.UnitedStates, CountryISO.UnitedKingdom, CountryISO.UnitedArabEmirates];
	separateDialCode = false;
	eventURL: any;
	private calendlyListener = (e: MessageEvent) => {
		if (e.data?.event === 'calendly.event_scheduled') {
			this.eventURL = e.data?.payload?.event?.uri;
			this.sendCalendlyEmail();
		}
	};

	constructor(
		public contactservice: ContactService,
		private toastr: ToastrManager,
		public route: ActivatedRoute,
		private formBuilder: FormBuilder,
		private pageservice: PageService,
		private metaTagService: Meta,
		private titleService: Title,
		private lazyLoader: LazyLoaderService
	) {
		this.get_PageMeta();
		this.baseUrl = environment.baseUrl + '/assets';
		this.selectedSub = this.route.snapshot.paramMap.get('id');
		this.addCareerForm = this.formBuilder.group({
			name: ['', Validators.required],
			email: ['', [Validators.required, Validators.email, Validators.pattern('^[a-z0-9._%+-]+@[a-z0-9.-]+\\.[a-z]{2,4}$')]],
			message: ['', Validators.required],
			phone: ['', Validators.required]
		});
	}

	url = 'https://calendly.com/pixtar/explore';

	ngOnInit(): void {
		if (typeof window !== 'undefined') {
			this.waitForCalendly();
			window.addEventListener('message', this.calendlyListener);
		}
		this.focusPageTop();
		this.toggleGlobalChrome(true);
		this.applyInitialSubjectState();
	}

	private waitForCalendly(attempts = 0): void {
		if (window.Calendly) {
			this.initCalendlyWidget();
		} else if (attempts < 20) {
			setTimeout(() => this.waitForCalendly(attempts + 1), 300);
		} else {
			console.warn('Calendly failed to load');
		}
	}

	private initCalendlyWidget(): void {
		const el = document.querySelector('.calendly-inline-widget');
		if (!el || !window.Calendly) return;
		window.Calendly.initInlineWidget({
			url: this.url,
			parentElement: el,
			prefill: {}
		});
	}

	ngOnDestroy(): void {
		window.removeEventListener('message', this.calendlyListener);
	}

	private focusPageTop(): void {
		setTimeout(() => {
			window.scroll({ top: 0, left: 0, behavior: 'smooth' });
		}, 500);
	}

	private toggleGlobalChrome(show: boolean): void {
		const method: 'add' | 'remove' = show ? 'remove' : 'add';
		document.querySelectorAll('nav, footer').forEach((el) => el.classList[method]('d-none'));
	}

	private applyInitialSubjectState(): void {
		const map: Record<string, () => void> = {
			branding: () => this.setSubjectState('branding', true),
			website: () => this.setSubjectState('website', true),
			graphic: () => this.setSubjectState('graphic', true),
			eCommerce: () => this.setSubjectState('eCommerce', true),
			seo: () => this.setSubjectState('seo', true)
		};

		map[this.selectedSub ?? '']?.();
	}

	private setSubjectState(selector: string, active: boolean): void {
		document.querySelectorAll(`.${selector}`).forEach((el) => el.classList.toggle('active', active));
		switch (selector) {
			case 'website':
				this.isWebsitesel = active;
				break;
			case 'branding':
				this.isBrandingsel = active;
				break;
			case 'graphic':
				this.isGraphicsel = active;
				break;
			case 'eCommerce':
				this.isEcommerce = active;
				break;
			case 'seo':
				this.isSeosel = active;
				break;
		}
	}


	get_PageMeta() {
		let obj = { pageName: 'contact' };
		this.pageservice.getpageWithName(obj).subscribe(
			(response) => {
				if (response.body.code == 200) {
					if (response.body.result) {
						this.titleService.setTitle(response?.body.result.meta_title);
						// this.metaTagService.addTags([
						// 	{ name: 'description', content: response?.body.result.meta_description },
						// 	{ name: 'keywords', content: response?.body.result.meta_keywords },
						// ]);
						if (this.selectedSub) {
							this.metaTagService.updateTag({ name: 'description', content: this.selectedSub + ' - ' + response?.body.result.meta_description });
							this.metaTagService.updateTag({ name: 'keywords', content: this.selectedSub + ' - ' + response?.body.result.meta_keywords });
							this.metaTagService.updateTag({ rel: 'canonical', href: 'https://www.pixtar.ae/contact' });
						} else {
							this.metaTagService.updateTag({ name: 'description', content: response?.body.result.meta_description });
							this.metaTagService.updateTag({ name: 'keywords', content: response?.body.result.meta_keywords });
							this.metaTagService.updateTag({ rel: 'canonical', href: 'https://www.pixtar.ae/contact' });
						}
					}
				} else if (response.body.code == 400) {
				}
				else {

				}

			},
		);
	}

	public hasError = (controlName: string, errorName: string) => {
		return this.addCareerForm.controls[controlName].hasError(errorName);
	};

	public hasEmailError = (controlName: string, errorName: string) => {
		if (this.addCareerForm.controls['email'].value == "") {
			return "Email is required";
		} else if (this.addCareerForm.controls['email'].status == "INVALID") {
			return "Invalid Email";
		} else {
			return this.addCareerForm.controls['email'].hasError(errorName);
		}
	};

	public hasPhoneNumberError = (controlName: string, errorName: string) => {
		if (this.addCareerForm.controls['phone'].value == "") {
			return "Phone Number is required";
		} else if (this.addCareerForm.controls['phone'].status == "INVALID") {
			return "Invalid Phone Number";
		} else {
			return this.addCareerForm.controls['phone'].hasError(errorName);
		}
	};
	onSubmit() {
		this.submitted = true;
		this.subject = [];
		let obj = this.addCareerForm.value;
		if (this.addCareerForm.invalid) {
			return false;
		}
		if (this.isBrandingsel) {
			this.subject.push('Branding');
		}
		if (this.isWebsitesel) {
			this.subject.push('Website');
		}
		if (this.isGraphicsel) {
			this.subject.push('Graphic');
		}
		// if(this.isEnterpricesel){
		//   this.subject.push('Enterprise Solution');
		// }
		if (this.isEcommerce) {
			this.subject.push('eCommerce');
		}
		if (this.isSeosel) {
			this.subject.push('SEO');
		}
		obj['subject'] = this.subject.toString();
		if (this.subject.length < 1) {
			this.toastr.errorToastr("Please Select any one from subjects");
			return false;
		}
		obj['phone'] = obj.phone.internationalNumber;
		return this.contactservice.addContact(obj).subscribe(response => {
			if (response && response.body.code == 200) {
				this.submitted = true;
				this.toastr.successToastr(response.body.message);
				setInterval(() => {
					window.location.reload();
				}, 2000);

			} else {
				this.toastr.errorToastr("Error");
			}
		},
			error => this.error = error
		);
	}

	selectSub(type: string) {
		const selector = type;
		const isActive = document.querySelector(`.${selector}`)?.classList.contains('active');
		this.setSubjectState(selector, !isActive);
	}

	sendCalendlyEmail() {
		let obj: any = {};
		obj['eventUri'] = this.eventURL;
		return this.contactservice.SendCalendlyEmail(obj).subscribe(response => {
			if (response && response.body.code == 200) {
				this.submitted = true;
				this.toastr.successToastr(response.body.message);
				setInterval(() => {
					window.location.reload();
				}, 2000);

			} else {
				this.toastr.errorToastr("Error");
			}
		},
			error => this.error = error
		);
	}
}
